let profile = JSON.parse(localStorage.getItem("caretrackProfile")) || {};
let symptoms = JSON.parse(localStorage.getItem("caretrackSymptoms")) || [];
let results = [];
let diseases = []; // This will hold the data from MongoDB

document.addEventListener("DOMContentLoaded", async function () {
  // Added 'async' here
  // 1. Display profile and symptoms as before
  document.getElementById("profileBox").innerHTML = `
        <b>Name:</b> ${profile.name || "-"} <br>
        <b>Age:</b> ${profile.age || "-"} <br>
        <b>Gender:</b> ${profile.gender || "-"} <br>
        <b>Blood Group:</b> ${profile.blood || "-"} <br>
        <b>Phone:</b> ${profile.phone || "-"} <br>
        <b>Email:</b> ${profile.email || "-"} <br>
        <b>Height:</b> ${profile.height || "-"} <br>
        <b>Weight:</b> ${profile.weight || "-"} <br>
        <b>Address:</b> ${profile.address || "-"}
    `;

  document.getElementById("symptomBox").innerHTML = symptoms.length
    ? symptoms.join(", ")
    : "No symptoms selected";

  // 2. NEW: Fetch the diseases from your MongoDB Server
  try {
    const response = await fetch("http://localhost:3000/get-diseases");
    diseases = await response.json();
    console.log("Successfully loaded from MongoDB!");

    // 3. Run analysis ONLY after data is received
    runAnalysis();
  } catch (error) {
    console.error("Database connection failed:", error);
    document.getElementById("results").innerHTML =
      "Error: Could not reach the medical database.";
  }
});

function runAnalysis() {
  results = [];
  if (symptoms.length === 0) {
    document.getElementById("results").innerHTML =
      "Please select symptoms first.";
    return;
  }

  // This now loops through the 'diseases' we got from MongoDB
  diseases.forEach((disease) => {
    let matchCount = 0;
    // Ensure we check for 'symptoms' (with the correct spelling)
    const dbSymptoms = disease.symptoms || disease.symtoms || [];

    dbSymptoms.forEach((s) => {
      if (symptoms.includes(s)) {
        matchCount++;
      }
    });

    if (matchCount > 0) {
      let probability = Math.round((matchCount / dbSymptoms.length) * 100);
      results.push({
        name: disease.name,
        risk: disease.risk,
        doctor: disease.doctor,
        probability: probability,
      });
    }
  });

  results.sort((a, b) => b.probability - a.probability);
  displayResults();
}

// The rest of your functions (displayResults, downloadPDF) stay exactly the same!
function displayResults() {
  let html = "";
  if (results.length === 0) {
    html = "No matching conditions found.";
  }
  results.forEach((d) => {
    html += `
            <div class="card">
                <h3><u>${d.name}:</u></h3>
                <p><b>Match Probability:</b> ${d.probability}%</p>
                <p><b>Risk Level:</b> ${d.risk}</p>
                <p><b>Recommended Doctor:</b> ${d.doctor}</p>
            </div>
        `;
  });
  document.getElementById("results").innerHTML = html;
}

function downloadPDF() {
  const { jsPDF } = window.jspdf;
  const doc = new jsPDF();

  const pageWidth = doc.internal.pageSize.getWidth();
  const pageHeight = doc.internal.pageSize.getHeight();

  let y = 20;

  // ===== LOGO (LEFT) =====
  const logo =
    "";
  doc.addImage(logo, "PNG", 20, 10, 25, 25);

  // ===== TITLE CENTER =====
  doc.setFont("helvetica", "bold");
  doc.setFontSize(26);
  doc.setTextColor(0, 0, 0);
  doc.text("CareTrack", pageWidth / 2, 22, { align: "center" });

  doc.setFontSize(12);
  doc.setTextColor(80);
  doc.text("Medical Health Report", pageWidth / 2, 30, { align: "center" });

  // ===== LINE =====
  doc.setDrawColor(0, 150, 120);
  doc.setLineWidth(0.7);
  doc.line(20, 38, pageWidth - 20, 38);

  // ===== DATE =====
  let now = new Date();
  doc.setFontSize(9);
  doc.setTextColor(100);
  doc.text(`Generated: ${now.toLocaleString()}`, pageWidth - 20, 45, {
    align: "right",
  });

  y = 55;

  // ===== PATIENT INFO =====
  doc.setFontSize(14);
  doc.setTextColor(0, 100, 120);
  doc.setFont("helvetica", "bold");
  doc.text("Patient Information", 20, y);

  y += 8;

  const info = [
    ["Name", profile.name],
    ["Age", profile.age],
    ["Gender", profile.gender],
    ["Blood Group", profile.blood],
    ["Phone", profile.phone],
    ["Email", profile.email],
    ["Height", profile.height],
    ["Weight", profile.weight],
    ["Address", profile.address],
  ];

  doc.setFontSize(11);

  info.forEach((item) => {
    doc.setFont("helvetica", "bold");
    doc.setTextColor(0);
    doc.text(item[0] + ":", 20, y);

    doc.setFont("helvetica", "normal");
    doc.text(item[1] || "-", 60, y);

    y += 7;
  });

  y += 5;

  // ===== SYMPTOMS =====
  doc.setFont("helvetica", "bold");
  doc.setTextColor(0, 100, 120);
  doc.setFontSize(14);
  doc.text("Reported Symptoms", 20, y);

  y += 8;

  doc.setFont("helvetica", "normal");
  doc.setTextColor(0);

  symptoms.forEach((s) => {
    doc.text("• " + s, 25, y);
    y += 6;
  });

  y += 5;

  // ===== CONDITIONS =====
  doc.setFont("helvetica", "bold");
  doc.setTextColor(0, 100, 120);
  doc.setFontSize(14);
  doc.text("Possible Conditions", 20, y);

  y += 10;

  results.forEach((r) => {
    // Color based on risk
    let color;
    if (r.risk === "High") color = [255, 80, 80];
    else if (r.risk === "Medium") color = [255, 180, 0];
    else color = [0, 180, 100];

    doc.setDrawColor(220);
    doc.setFillColor(245, 245, 245);
    doc.roundedRect(20, y - 5, pageWidth - 40, 26, 3, 3, "F");

    doc.setFont("helvetica", "bold");
    doc.setFontSize(12);
    doc.setTextColor(0);
    doc.text(r.name, 25, y);

    doc.setFont("helvetica", "normal");
    doc.setFontSize(10);

    doc.text(`Match: ${r.probability}%`, 25, y + 7);

    doc.setTextColor(...color);
    doc.text(`Risk: ${r.risk}`, 90, y + 7);

    doc.setTextColor(0);
    doc.text(`Doctor: ${r.doctor}`, 25, y + 14);

    y += 32;

    // ===== PAGE BREAK =====
    if (y > 260) {
      addFooter(doc);
      doc.addPage();
      y = 20;
    }
  });

  // ===== FINAL FOOTER =====
  addFooter(doc);

  doc.save(`CareTrack_Report_${profile.name || "Patient"}.pdf`);
}

// ===== FOOTER FUNCTION =====
function addFooter(doc) {
  const pageWidth = doc.internal.pageSize.getWidth();
  const pageHeight = doc.internal.pageSize.getHeight();

  doc.setFontSize(8);
  doc.setTextColor(120);

  doc.text(
    "© 2026 CARETRACK AI | Confidential Medical Report",
    pageWidth / 2,
    pageHeight - 10,
    { align: "center" },
  );
}
